import React, { useState, useEffect, useRef } from 'react';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import 'leaflet.heat';
import { api } from '../api';
import { useToast } from '../hooks/useToast';
import Toast from './Toast';

const MapaCalor = ({ token }) => {
  const mapRef = useRef(null);
  const mapInstanceRef = useRef(null);
  const heatLayerRef = useRef(null);
  const [accidentes, setAccidentes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [mesSeleccionado, setMesSeleccionado] = useState(null);
  const [estadisticas, setEstadisticas] = useState({ total: 0, fatales: 0, conHeridos: 0, soloDanos: 0 });
  const [mostrarFormulario, setMostrarFormulario] = useState(false);
  const { toasts, removeToast, toast } = useToast();

  const FORM_INICIAL = {
    latitud: 10.3910,
    longitud: -75.4794,
    fecha_hora: new Date().toISOString().slice(0, 16),
    gravedad: 'leve',
    tipo_vehiculo: 'automovil',
    clima: 'soleado',
    estado_via: 'bueno',
    dia_festivo: false,
    hora_pico: false,
    descripcion: '',
  };
  const [nuevoReporte, setNuevoReporte] = useState(FORM_INICIAL);

  const CARTAGENA_CENTER = [10.3910, -75.4794];
  const meses = [
    { nombre: 'Feb', valor: 2, barras: 1 },
    { nombre: 'Mar', valor: 3, barras: 2 },
    { nombre: 'Apr', valor: 4, barras: 3 },
    { nombre: 'May', valor: 5, barras: 4 },
    { nombre: 'Jun', valor: 6, barras: 5 },
    { nombre: 'Jul', valor: 7, barras: 2 },
    { nombre: 'Aug', valor: 8, barras: 4 },
    { nombre: 'Sep', valor: 9, barras: 2 },
  ];

  const causas = [
    { nombre: 'Exceso velocidad', valor: 38, color: '#F44336' },
    { nombre: 'Imprudencia', valor: 28, color: '#FF9800' },
    { nombre: 'Alcohol', valor: 19, color: '#FFC107' },
    { nombre: 'Otros', valor: 13, color: '#2196F3' },
  ];

  useEffect(() => {
    if (!mapInstanceRef.current && mapRef.current) {
      mapInstanceRef.current = L.map(mapRef.current, { zoomControl: false }).setView(CARTAGENA_CENTER, 12);

      L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png', {
        attribution: '©OpenStreetMap, ©CartoDB',
      }).addTo(mapInstanceRef.current);

      L.control.zoom({ position: 'topleft' }).addTo(mapInstanceRef.current);
    }

    cargarAccidentes();

    return () => {
      if (mapInstanceRef.current) {
        mapInstanceRef.current.remove();
        mapInstanceRef.current = null;
      }
    };
  }, []);

  const cargarAccidentes = async () => {
    try {
      const data = await api.get('/api/accidentes');
      setAccidentes(data);
      calcularEstadisticas(data);
      actualizarMapaCalor(data);
      setLoading(false);
    } catch (error) {
      console.error('Error cargando accidentes:', error);
      setLoading(false);
    }
  };

  const calcularEstadisticas = (data) => {
    setEstadisticas({
      total: data.length,
      fatales: data.filter((a) => a.gravedad === 'fatal').length,
      conHeridos: data.filter((a) => a.gravedad === 'grave').length,
      soloDanos: data.filter((a) => a.gravedad === 'leve').length,
    });
  };

  const actualizarMapaCalor = (data) => {
    if (!mapInstanceRef.current) return;
    if (heatLayerRef.current) mapInstanceRef.current.removeLayer(heatLayerRef.current);

    const pesoGravedad = { fatal: 1.0, grave: 0.7, leve: 0.4 };
    const puntos = data.map((a) => [a.latitud, a.longitud, pesoGravedad[a.gravedad] || 0.5]);

    heatLayerRef.current = L.heatLayer(puntos, {
      radius: 35,
      blur: 35,
      maxZoom: 17,
      minOpacity: 0.4,
      gradient: {
        0.2: '#3b82f6',
        0.4: '#00ff00',
        0.6: '#ffff00',
        0.8: '#ff8800',
        1.0: '#ff0000',
      },
    }).addTo(mapInstanceRef.current);
  };

  const handleSubmitReporte = async (e) => {
    e.preventDefault();
    try {
      await api.post('/api/accidentes/reportar', {
        ...nuevoReporte,
        latitud: parseFloat(nuevoReporte.latitud),
        longitud: parseFloat(nuevoReporte.longitud),
      });
      toast.success('Reporte enviado. Será revisado por un administrador.');
      setMostrarFormulario(false);
      setNuevoReporte(FORM_INICIAL);
      cargarAccidentes();
    } catch (error) {
      toast.error(`Error al enviar reporte: ${error.message}`);
    }
  };

  const seleccionarEnMapa = () => {
    toast.info('Haz clic en el mapa para seleccionar la ubicación');
    mapInstanceRef.current.once('click', (e) => {
      setNuevoReporte((prev) => ({
        ...prev,
        latitud: parseFloat(e.latlng.lat.toFixed(6)),
        longitud: parseFloat(e.latlng.lng.toFixed(6)),
      }));

      L.marker(e.latlng, {
        icon: L.divIcon({
          className: 'marker-temp',
          html: '<div style="font-size: 30px;">📍</div>',
          iconSize: [30, 30],
        }),
      }).addTo(mapInstanceRef.current).bindPopup('Nueva ubicación seleccionada').openPopup();
    });
  };

  if (loading) {
    return (
      <div className="loading-overlay">
        <div className="spinner"></div>
        <p>Cargando mapa de calor...</p>
      </div>
    );
  }

  return (
    <div className="crashmap-layout">
      <Toast toasts={toasts} onRemove={removeToast} />

      {/* Panel Izquierdo - Timeline */}
      <div className="crashmap-sidebar-left">
        <div className="crashmap-logo">
          <div className="logo-icon">🚗</div>
          <div className="logo-text">CRASHMAP</div>
        </div>

        <div className="timeline-meses">
          {meses.map((mes, idx) => (
            <div
              key={idx}
              className={`mes-item ${mesSeleccionado === mes.valor ? 'active' : ''}`}
              onClick={() => setMesSeleccionado(mesSeleccionado === mes.valor ? null : mes.valor)}
            >
              <div className="mes-barras">
                {[...Array(mes.barras)].map((_, i) => (
                  <div key={i} className={`barra barra-${i}`}></div>
                ))}
              </div>
              <span className="mes-nombre">{mes.nombre}</span>
            </div>
          ))}
        </div>

        <button className="btn-export-pdf">
          <span>📥</span> Export PDF
        </button>
      </div>

      {/* Mapa Central */}
      <div className="crashmap-main">
        <div className="map-header">
          <span className="map-location">📍 Leaflet | ©OpenStreetMap, ©CartoDB</span>
        </div>
        <div ref={mapRef} className="mapa-crashmap"></div>

        <button className="btn-reportar-flotante" onClick={() => setMostrarFormulario(true)}>
          <span>➕</span>
          <span>Reportar Accidente</span>
        </button>
      </div>

      {/* Panel Derecho - Estadísticas */}
      <div className="crashmap-sidebar-right">
        <div className="stats-tabs-container">
          <button className="stat-tab active"><span>🚗</span> Etapas</button>
          <button className="stat-tab"><span>📊</span> Análisis</button>
        </div>

        <div className="stats-card">
          <div className="stats-header">
            <div className="stats-icon-circle">🚗</div>
            <span className="stats-title">Accidentes registrados</span>
            <button className="stats-dropdown">▼</button>
          </div>
          <div className="stats-grid-main">
            <div className="stat-box"><div className="stat-number">{estadisticas.total}</div><div className="stat-label">Total</div></div>
            <div className="stat-box"><div className="stat-number">{estadisticas.fatales}</div><div className="stat-label">Fatales</div></div>
            <div className="stat-box"><div className="stat-number">{estadisticas.conHeridos}</div><div className="stat-label">Con heridos</div></div>
            <div className="stat-box"><div className="stat-number">{estadisticas.soloDanos}</div><div className="stat-label">Solo daños</div></div>
          </div>
        </div>

        <div className="stats-card">
          <div className="stats-header">
            <div className="stats-icon-circle" style={{ background: '#4CAF50' }}>✓</div>
            <span className="stats-title">Causas determinadas</span>
            <button className="stats-dropdown">▼</button>
          </div>
          <div className="causas-section">
            <div className="causas-lista-crashmap">
              {causas.map((causa, idx) => (
                <div key={idx} className="causa-item-crashmap">
                  <div className="causa-barra-container">
                    <div className="causa-barra-fill" style={{ width: `${causa.valor}%`, background: causa.color }}></div>
                  </div>
                  <div className="causa-info-row">
                    <span className="causa-nombre-crashmap">{causa.nombre}</span>
                    <span className="causa-valor">{causa.valor}%</span>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>

      {/* Modal Formulario Reporte */}
      {mostrarFormulario && (
        <div className="modal-overlay-crashmap" onClick={() => setMostrarFormulario(false)}>
          <div className="modal-crashmap" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header-crashmap">
              <h2>📝 Reportar Nuevo Accidente</h2>
              <button className="btn-cerrar-crashmap" onClick={() => setMostrarFormulario(false)}>✕</button>
            </div>

            <form onSubmit={handleSubmitReporte} className="form-crashmap">
              <div className="form-section">
                <h3>📍 Ubicación</h3>
                <div className="form-row">
                  <div className="form-group-crashmap">
                    <label>Latitud</label>
                    <input type="number" step="0.000001" value={nuevoReporte.latitud}
                      onChange={(e) => setNuevoReporte({ ...nuevoReporte, latitud: e.target.value })} required />
                  </div>
                  <div className="form-group-crashmap">
                    <label>Longitud</label>
                    <input type="number" step="0.000001" value={nuevoReporte.longitud}
                      onChange={(e) => setNuevoReporte({ ...nuevoReporte, longitud: e.target.value })} required />
                  </div>
                </div>
                <button type="button" className="btn-seleccionar-mapa" onClick={seleccionarEnMapa}>
                  📍 Seleccionar en el mapa
                </button>
              </div>

              <div className="form-section">
                <h3>📅 Detalles del Incidente</h3>
                <div className="form-row">
                  <div className="form-group-crashmap">
                    <label>Fecha y Hora</label>
                    <input type="datetime-local" value={nuevoReporte.fecha_hora}
                      onChange={(e) => setNuevoReporte({ ...nuevoReporte, fecha_hora: e.target.value })} required />
                  </div>
                  <div className="form-group-crashmap">
                    <label>Gravedad</label>
                    <select value={nuevoReporte.gravedad}
                      onChange={(e) => setNuevoReporte({ ...nuevoReporte, gravedad: e.target.value })}>
                      <option value="leve">Leve (solo daños)</option>
                      <option value="grave">Grave (con heridos)</option>
                      <option value="fatal">Fatal</option>
                    </select>
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group-crashmap">
                    <label>Tipo de Vehículo</label>
                    <select value={nuevoReporte.tipo_vehiculo}
                      onChange={(e) => setNuevoReporte({ ...nuevoReporte, tipo_vehiculo: e.target.value })}>
                      <option value="automovil">Automóvil</option>
                      <option value="moto">Motocicleta</option>
                      <option value="bus">Bus</option>
                      <option value="camion">Camión</option>
                      <option value="bicicleta">Bicicleta</option>
                    </select>
                  </div>
                  <div className="form-group-crashmap">
                    <label>Condiciones Climáticas</label>
                    <select value={nuevoReporte.clima}
                      onChange={(e) => setNuevoReporte({ ...nuevoReporte, clima: e.target.value })}>
                      <option value="soleado">Soleado</option>
                      <option value="nublado">Nublado</option>
                      <option value="lluvia">Lluvia</option>
                    </select>
                  </div>
                </div>
                <div className="form-row">
                  <div className="form-group-crashmap">
                    <label>Estado de la Vía</label>
                    <select value={nuevoReporte.estado_via}
                      onChange={(e) => setNuevoReporte({ ...nuevoReporte, estado_via: e.target.value })}>
                      <option value="bueno">Bueno</option>
                      <option value="regular">Regular</option>
                      <option value="malo">Malo</option>
                    </select>
                  </div>
                  <div className="form-group-crashmap checkboxes">
                    <label className="checkbox-label">
                      <input type="checkbox" checked={nuevoReporte.dia_festivo}
                        onChange={(e) => setNuevoReporte({ ...nuevoReporte, dia_festivo: e.target.checked })} />
                      <span>Día festivo</span>
                    </label>
                    <label className="checkbox-label">
                      <input type="checkbox" checked={nuevoReporte.hora_pico}
                        onChange={(e) => setNuevoReporte({ ...nuevoReporte, hora_pico: e.target.checked })} />
                      <span>Hora pico</span>
                    </label>
                  </div>
                </div>
                <div className="form-group-crashmap">
                  <label>Descripción</label>
                  <textarea value={nuevoReporte.descripcion}
                    onChange={(e) => setNuevoReporte({ ...nuevoReporte, descripcion: e.target.value })}
                    rows="4" placeholder="Describe lo que sucedió..." />
                </div>
              </div>

              <div className="form-actions">
                <button type="button" className="btn-cancelar-crashmap" onClick={() => setMostrarFormulario(false)}>Cancelar</button>
                <button type="submit" className="btn-enviar-crashmap">📤 Enviar Reporte</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default MapaCalor;
